#!/usr/bin/env python3
"""Review approval-process metadata for missing actions and step definitions."""

from __future__ import annotations

import argparse
import json
import sys
import xml.etree.ElementTree as ET
from pathlib import Path

SUFFIX = ".approvalProcess-meta.xml"
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def local_name(tag: str) -> str:
    return tag.split("}", 1)[-1]

def iter_files(paths: list[Path]) -> list[Path]:
    files: list[Path] = []
    for path in paths:
        if path.is_dir():
            files.extend(candidate for candidate in path.rglob(f"*{SUFFIX}") if candidate.is_file())
        elif path.is_file() and path.name.endswith(SUFFIX):
            files.append(path)
    return sorted(set(files))

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(finding) for finding in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_file(path: Path) -> list[str]:
    findings: list[str] = []
    root = ET.parse(path).getroot()
    child_tags = [local_name(child.tag) for child in root]

if "approvalStep" not in child_tags:
        findings.append(f"HIGH {path}: no approval steps defined")
    if "initialSubmissionActions" not in child_tags:
        findings.append(f"REVIEW {path}: no initial submission actions configured")
    if "finalApprovalActions" not in child_tags:
        findings.append(f"REVIEW {path}: no final approval actions configured")
    if "finalRejectionActions" not in child_tags:
        findings.append(f"REVIEW {path}: no final rejection actions configured")

return findings

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Scan Salesforce approval-process metadata for missing steps or action blocks."
    )
    parser.add_argument("paths", nargs="+", help="Approval-process files or directories")
    args = parser.parse_args()

files = iter_files([Path(value) for value in args.paths])
    if not files:
        return emit_result(
            ["HIGH no approval-process metadata files found"],
            "Scanned 0 approval-process metadata files; no files matched the provided paths.",
        )

findings: list[str] = []
    for path in files:
        findings.extend(audit_file(path))

summary = (
        f"Scanned {len(files)} approval-process metadata file(s); "
        f"{len(findings)} finding(s) detected."
    )
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Audit deployment manifests and metadata folders for common release risks."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

RISKY_TYPES = {"SharingRules", "ConnectedApp", "ExternalCredential", "NamedCredential"}
TEXT_SUFFIXES = {".xml", ".cls", ".trigger", ".js", ".json", ".yaml", ".yml"}
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def iter_files(paths: list[str]) -> list[Path]:
    files: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_file():
            files.append(path)
        elif path.is_dir():
            files.extend(candidate for candidate in path.rglob("*") if candidate.is_file())
        else:
            files.append(path)
    return files

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(finding) for finding in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_package_xml(path: Path, text: str) -> list[str]:
    findings: list[str] = []
    if "<version>" not in text:
        findings.append(f"HIGH {path}: package.xml is missing an API version")

if re.search(r"<name>\s*Profile\s*</name>", text):
        findings.append(f"MEDIUM {path}: manifest includes Profile metadata; review for accidental broad access changes")

for metadata_type in RISKY_TYPES:
        if re.search(rf"<name>\s*{metadata_type}\s*</name>", text):
            findings.append(f"HIGH {path}: manifest includes {metadata_type}; require explicit review and smoke tests")

wildcard_pattern = re.compile(
        r"<members>\s*\*\s*</members>\s*<name>\s*(Flow|Profile|PermissionSet|CustomObject)\s*</name>",
        re.MULTILINE,
    )
    for match in wildcard_pattern.finditer(text):
        findings.append(f"MEDIUM {path}: wildcard deployment for `{match.group(1)}` reduces review precision")

return findings

def audit_file(path: Path) -> list[str]:
    findings: list[str] = []
    if not path.exists():
        return [f"HIGH {path}: file not found"]
    if path.suffix.lower() not in TEXT_SUFFIXES and path.name != "package.xml":
        return findings

text = path.read_text(encoding="utf-8", errors="ignore")
    lower_path = str(path).lower()

if path.name == "package.xml":
        findings.extend(audit_package_xml(path, text))

if "/profiles/" in lower_path or path.name.endswith(".profile-meta.xml"):
        findings.append(f"MEDIUM {path}: profile deployment detected; prefer permission-set-focused releases where possible")

if "/flows/" in lower_path and "<status>Active</status>" in text:
        findings.append(f"LOW {path}: active Flow metadata present; confirm activation timing and smoke tests")

if any(token in lower_path for token in ("connectedapp", "namedcredential", "externalcredential")):
        findings.append(f"HIGH {path}: integration metadata present; verify environment-specific config and rollback")

return findings

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check deployment manifests and metadata folders for release-risk indicators."
    )
    parser.add_argument("paths", nargs="+", help="Manifest files or metadata directories to inspect")
    args = parser.parse_args()

files = iter_files(args.paths)
    findings: list[str] = []
    for path in files:
        findings.extend(audit_file(path))

if not files:
        findings.append("HIGH no manifest or metadata files matched the provided paths")

summary = (
        f"Scanned {len(files)} manifest or metadata file(s); "
        f"{len(findings)} finding(s) detected."
    )
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Audit connected-app and auth-related files for common security anti-patterns."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

TEXT_SUFFIXES = {".xml", ".json", ".cls", ".trigger", ".js", ".ts", ".md", ".txt"}
DIRECT_ENDPOINT_PATTERN = re.compile(r"setEndpoint\(\s*['\"]https?://", re.IGNORECASE)
SECRET_PATTERN = re.compile(
    r"authorization:\s*bearer\s+[A-Za-z0-9._-]+|client[_-]?secret|consumersecret|password\s*=",
    re.IGNORECASE,
)
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def iter_files(paths: list[str]) -> list[Path]:
    files: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_file():
            files.append(path)
        elif path.is_dir():
            files.extend(candidate for candidate in path.rglob("*") if candidate.is_file())
        else:
            files.append(path)
    return files

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(finding) for finding in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_file(path: Path) -> tuple[list[str], bool]:
    findings: list[str] = []
    found_named_credential = False

if not path.exists():
        return [f"HIGH {path}: file not found"], found_named_credential
    if path.suffix.lower() not in TEXT_SUFFIXES:
        return findings, found_named_credential

text = path.read_text(encoding="utf-8", errors="ignore")
    lower_path = str(path).lower()

if "namedcredential" in lower_path or "externalcredential" in lower_path or path.name.endswith(".namedCredential-meta.xml"):
        found_named_credential = True

if SECRET_PATTERN.search(text):
        findings.append(f"HIGH {path}: possible hardcoded secret, bearer token, or password material found")

if DIRECT_ENDPOINT_PATTERN.search(text):
        findings.append(f"MEDIUM {path}: direct HTTPS endpoint in code; prefer Named Credentials and `callout:` references")

if re.search(r"username[- ]password|password flow", text, re.IGNORECASE):
        findings.append(f"HIGH {path}: username-password flow reference found; review for stronger OAuth alternative")

if re.search(r"<scope>\s*full\s*</scope>|[\s,]full[\s,]", text, re.IGNORECASE):
        findings.append(f"MEDIUM {path}: broad `full` OAuth scope detected; confirm least-privilege need")

return findings, found_named_credential

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check connected-app, Named Credential, and integration auth files for risky patterns."
    )
    parser.add_argument("paths", nargs="+", help="Files or directories to inspect")
    args = parser.parse_args()

findings: list[str] = []
    named_credential_found = False
    files = iter_files(args.paths)
    for path in files:
        file_findings, file_has_named_credential = audit_file(path)
        findings.extend(file_findings)
        named_credential_found = named_credential_found or file_has_named_credential

if findings and not named_credential_found:
        findings.append("LOW no Named Credential or External Credential metadata detected in scanned paths")

if not files:
        findings.append("HIGH no connected-app or auth-related files matched the provided paths")

summary = (
        f"Scanned {len(files)} connected-app or auth-related file(s); "
        f"{len(findings)} finding(s) detected."
    )
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

# Namespace used in Salesforce field XML files
SF_NS = "http://soap.sforce.com/2006/04/metadata"

def _tag(name: str) -> str:
    """Return a namespace-qualified XML tag name."""
    return f"{{{SF_NS}}}{name}"

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description=(
            "Check Salesforce metadata for common custom field anti-patterns. "
            "Point --manifest-dir at the root of your SFDX source tree or "
            "retrieved metadata directory."
        ),
    )
    parser.add_argument(
        "--manifest-dir",
        default=".",
        help="Root directory of the Salesforce metadata (default: current directory).",
    )
    return parser.parse_args()

def check_field_file(field_file: Path) -> list[str]:
    """Parse one .field-meta.xml file and return a list of issue strings."""
    issues: list[str] = []

try:
        tree = ET.parse(field_file)
    except ET.ParseError as exc:
        issues.append(f"{field_file}: XML parse error — {exc}")
        return issues

root = tree.getroot()

# Check 2: Missing Help Text (not a hard error, but a quality warning)
    help_el = root.find(_tag("inlineHelpText"))
    if help_el is None or not (help_el.text or "").strip():
        issues.append(
            f"{full_name}: No Help Text (inlineHelpText) set. "
            f"Help Text improves user experience and admin maintainability."
        )

# Check 3: Long Text Area at minimum size (256 chars)
    if field_type == "LongTextArea":
        length_el = root.find(_tag("length"))
        if length_el is not None and length_el.text:
            try:
                length = int(length_el.text.strip())
                if length <= 256:
                    issues.append(
                        f"{full_name}: Long Text Area is set to minimum size ({length} chars). "
                        f"Consider whether a larger size (e.g. 32768) is more appropriate "
                        f"for the expected content."
                    )
            except ValueError:
                pass

return issues

def check_custom_field_creation(manifest_dir: Path) -> list[str]:
    """Scan manifest_dir for .field-meta.xml files and return all issues found."""
    issues: list[str] = []

if not manifest_dir.exists():
        issues.append(f"Manifest directory not found: {manifest_dir}")
        return issues

field_files = list(manifest_dir.rglob("*.field-meta.xml"))

if not field_files:
        # Not an error — the directory may be a non-SFDX layout
        return issues

for field_file in sorted(field_files):
        issues.extend(check_field_file(field_file))

return issues

def main() -> int:
    args = parse_args()
    manifest_dir = Path(args.manifest_dir)
    issues = check_custom_field_creation(manifest_dir)

if not issues:
        print("No issues found.")
        return 0

for issue in issues:
        print(f"ISSUE: {issue}")

return 1

if __name__ == "__main__":
    sys.exit(main())

## Example 1: Deployable Case Routing Rules

**Context:** A support org routes Cases by region and priority. The first implementation hardcodes queue IDs in Apex and uses different values in each sandbox.

**Problem:** Deployments break because queue IDs differ by org. Admins are afraid to touch the routing logic because every environment needs manual code edits or post-deploy fixes.

**Solution:**

Create a `Case_Routing__mdt` type with fields such as `Region__c`, `Priority__c`, `Queue_Developer_Name__c`, `Active__c`, and `Sort_Order__c`.

```apex
public with sharing class CaseRoutingService {
    public static String queueDeveloperNameFor(String region, String priority) {
        for (Case_Routing__mdt rule : [
            SELECT DeveloperName, Region__c, Priority__c, Queue_Developer_Name__c, Active__c
            FROM Case_Routing__mdt
            WHERE Active__c = true
            ORDER BY Sort_Order__c ASC
        ]) {
            if (rule.Region__c == region && rule.Priority__c == priority) {
                return rule.Queue_Developer_Name__c;
            }
        }
        return null;
    }
}
```

def parse_xml(path: Path) -> ET.Element | None:
    try:
        return ET.parse(path).getroot()
    except ET.ParseError:
        return None

def line_number(text: str, index: int) -> int:
    return text.count("\n", 0, index) + 1

def find_cmdt_object_files(manifest_dir: Path) -> list[Path]:
    return sorted(path for path in manifest_dir.rglob("*.object-meta.xml") if path.stem.endswith("__mdt.object-meta"))

def field_files_for_object(object_file: Path) -> list[Path]:
    fields_dir = object_file.parent / "fields"
    if not fields_dir.exists():
        return []
    return sorted(fields_dir.glob("*.field-meta.xml"))

def object_visibility(root: ET.Element) -> str:
    for element in root.iter():
        if local_name(element.tag) == "visibility":
            return (element.text or "").strip()
    return ""

def field_name(field_root: ET.Element) -> str:
    for element in field_root.iter():
        if local_name(element.tag) == "fullName":
            return (element.text or "").strip()
    return ""

def check_object_visibility_and_fields(cmdt_object_files: list[Path]) -> list[str]:
    issues: list[str] = []

for object_file in cmdt_object_files:
        root = parse_xml(object_file)
        if root is None:
            issues.append(f"{object_file}: unable to parse custom metadata type definition.")
            continue

visibility = object_visibility(root)
        if visibility.lower() != "public":
            continue

for field_file in field_files_for_object(object_file):
            field_root = parse_xml(field_file)
            if field_root is None:
                issues.append(f"{field_file}: unable to parse field metadata.")
                continue
            api_name = field_name(field_root)
            if SECRET_RE.search(api_name):
                issues.append(
                    f"{field_file}: public custom metadata appears to contain a sensitive field name `{api_name}`; review whether the value belongs in Named Credentials or a protected package boundary."
                )

return issues

def check_custom_metadata_record_values(manifest_dir: Path) -> list[str]:
    issues: list[str] = []

for record_file in sorted(manifest_dir.rglob("*.md-meta.xml")):
        if "customMetadata" not in record_file.parts:
            continue

root = parse_xml(record_file)
        if root is None:
            issues.append(f"{record_file}: unable to parse custom metadata record.")
            continue

current_field = ""
        for element in root.iter():
            name = local_name(element.tag)
            text = (element.text or "").strip()
            if name == "field":
                current_field = text
            elif name == "value" and text:
                if current_field and SECRET_RE.search(current_field):
                    issues.append(
                        f"{record_file}: field `{current_field}` has a concrete value; review whether sensitive data is being stored in metadata."
                    )
                if HOST_RE.search(text):
                    issues.append(
                        f"{record_file}: metadata record contains a concrete host or environment-specific URL `{text}`; prefer Named Credentials or environment-safe indirection for endpoints."
                    )

return issues

def check_runtime_dml_usage(manifest_dir: Path) -> list[str]:
    issues: list[str] = []
    for path in sorted(manifest_dir.rglob("*")):
        if path.suffix not in {".cls", ".trigger"}:
            continue
        text = path.read_text(encoding="utf-8", errors="ignore")
        for match in APEX_DML_RE.finditer(text):
            issues.append(
                f"{path}:{line_number(text, match.start())}: appears to perform DML on `__mdt`; review whether runtime mutation has been designed into deployable metadata."
            )
    return issues

def check_custom_metadata_types(manifest_dir: Path) -> list[str]:
    issues: list[str] = []

if not manifest_dir.exists():
        return [f"Manifest directory not found: {manifest_dir}"]

cmdt_object_files = find_cmdt_object_files(manifest_dir)
    issues.extend(check_object_visibility_and_fields(cmdt_object_files))
    issues.extend(check_custom_metadata_record_values(manifest_dir))
    issues.extend(check_runtime_dml_usage(manifest_dir))

return issues

def main() -> int:
    args = parse_args()
    issues = check_custom_metadata_types(Path(args.manifest_dir))

if not issues:
        print("No issues found.")
        return 0

for issue in issues:
        print(f"ISSUE: {issue}")

return 1

if __name__ == "__main__":
    sys.exit(main())

def audit_csv(path: Path, required: list[str], external_id: str | None) -> list[str]:
    findings: list[str] = []
    with path.open(newline="", encoding="utf-8-sig") as handle:
        reader = csv.DictReader(handle)
        fieldnames = reader.fieldnames or []
        missing_columns = [column for column in required if column not in fieldnames]
        for column in missing_columns:
            findings.append(f"HIGH {path}: missing required column `{column}`")

seen_external_ids: set[str] = set()
        for index, row in enumerate(reader, start=2):
            for column in required:
                if column in row and not (row.get(column) or "").strip():
                    findings.append(f"MEDIUM {path}:{index}: blank value in required column `{column}`")

if external_id:
                value = (row.get(external_id) or "").strip()
                if not value:
                    findings.append(f"HIGH {path}:{index}: blank External ID in `{external_id}`")
                elif value in seen_external_ids:
                    findings.append(f"HIGH {path}:{index}: duplicate External ID `{value}`")
                else:
                    seen_external_ids.add(value)

#!/usr/bin/env python3
"""Audit Salesforce matching-rule and duplicate-rule metadata for common gaps."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def iter_rule_files(paths: list[str]) -> tuple[list[Path], list[Path]]:
    duplicate_rules: list[Path] = []
    matching_rules: list[Path] = []
    for raw in paths:
        path = Path(raw)
        candidates = [path] if path.is_file() else list(path.rglob("*")) if path.is_dir() else [path]
        for candidate in candidates:
            if not candidate.is_file():
                continue
            name = candidate.name
            if name.endswith(".duplicateRule-meta.xml"):
                duplicate_rules.append(candidate)
            elif name.endswith(".matchingRule-meta.xml"):
                matching_rules.append(candidate)
    return duplicate_rules, matching_rules

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(finding) for finding in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_duplicate_rule(path: Path) -> list[str]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")

if "<isActive>true</isActive>" not in text:
        findings.append(f"MEDIUM {path}: duplicate rule is not active")

if "actionOnInsert" not in text and "actionOnEdit" not in text:
        findings.append(f"HIGH {path}: duplicate rule has no insert/edit action configuration")

if re.search(r"<actionOnInsert>\s*Allow\s*</actionOnInsert>", text, re.IGNORECASE):
        findings.append(f"MEDIUM {path}: insert behavior allows save; confirm steward process for alerts")

if re.search(r"<actionOnEdit>\s*Allow\s*</actionOnEdit>", text, re.IGNORECASE):
        findings.append(f"LOW {path}: edit behavior allows save; verify whether this is intentional")

if "alertText" not in text:
        findings.append(f"LOW {path}: duplicate rule has no alert text for end users")

return findings

def audit_matching_rule(path: Path) -> list[str]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")
    field_count = len(re.findall(r"<field(?:Name)?>", text))

if field_count == 0:
        findings.append(f"HIGH {path}: matching rule appears to have no fields configured")
    elif field_count == 1:
        findings.append(f"MEDIUM {path}: matching rule uses a single field; confirm it is strong enough")

if "fuzzy" not in text.lower() and "exact" not in text.lower():
        findings.append(f"LOW {path}: matching method is not obvious from metadata text; review manually")

return findings

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check duplicate-rule and matching-rule metadata for activation, actions, and weak matching design."
    )
    parser.add_argument("paths", nargs="+", help="Metadata files or directories to inspect")
    args = parser.parse_args()

duplicate_rules, matching_rules = iter_rule_files(args.paths)
    findings: list[str] = []

if not duplicate_rules:
        findings.append("HIGH no duplicate rule metadata files found")
    if not matching_rules:
        findings.append("HIGH no matching rule metadata files found")

for path in duplicate_rules:
        findings.extend(audit_duplicate_rule(path))
    for path in matching_rules:
        findings.extend(audit_matching_rule(path))

total_files = len(duplicate_rules) + len(matching_rules)
    summary = (
        f"Scanned {total_files} duplicate-management metadata file(s); "
        f"{len(findings)} finding(s) detected."
    )
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Audit CRM Analytics dashboard and planning files for common anti-patterns."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

TEXT_SUFFIXES = {".json", ".wdash", ".xmd", ".md", ".txt"}
HOSTNAME_PATTERN = re.compile(
    r"https?://[A-Za-z0-9.-]*(salesforce|force)\.com|my\.salesforce\.com|lightning\.force\.com",
    re.IGNORECASE,
)
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def iter_files(paths: list[str]) -> list[Path]:
    files: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_file():
            files.append(path)
        elif path.is_dir():
            files.extend(candidate for candidate in path.rglob("*") if candidate.is_file())
        else:
            files.append(path)
    return files

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(finding) for finding in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def count_widgets(payload: object) -> int:
    total = 0
    if isinstance(payload, dict):
        for key, value in payload.items():
            if key == "widgets":
                if isinstance(value, dict):
                    total += len(value)
                elif isinstance(value, list):
                    total += len(value)
            total += count_widgets(value)
    elif isinstance(payload, list):
        for item in payload:
            total += count_widgets(item)
    return total

def has_filters(payload: object) -> bool:
    if isinstance(payload, dict):
        for key, value in payload.items():
            if key in {"filters", "filterpanel", "filterPanel"} and value:
                return True
            if has_filters(value):
                return True
    elif isinstance(payload, list):
        return any(has_filters(item) for item in payload)
    return False

def audit_file(path: Path, max_widgets: int) -> list[str]:
    findings: list[str] = []
    if not path.exists():
        return [f"HIGH {path}: file not found"]
    if path.suffix.lower() not in TEXT_SUFFIXES:
        return findings

text = path.read_text(encoding="utf-8", errors="ignore")
    if HOSTNAME_PATTERN.search(text):
        findings.append(f"MEDIUM {path}: hardcoded Salesforce hostname found; use environment-safe references")
    if "TODO" in text:
        findings.append(f"LOW {path}: unresolved TODO markers remain")

if path.suffix.lower() in {".json", ".wdash", ".xmd"}:
        try:
            payload = json.loads(text)
        except json.JSONDecodeError as exc:
            findings.append(f"MEDIUM {path}: invalid JSON ({exc.msg})")
            return findings

widgets = count_widgets(payload)
        if widgets > max_widgets:
            findings.append(
                f"MEDIUM {path}: dashboard appears to contain {widgets} widgets; trim to decision-focused views"
            )
        if widgets and not has_filters(payload):
            findings.append(f"LOW {path}: dashboard has widgets but no obvious filter configuration")

return findings

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check CRM Analytics files for hardcoded hostnames, oversized dashboards, and unfinished planning docs."
    )
    parser.add_argument("paths", nargs="+", help="Files or directories to inspect")
    parser.add_argument("--max-widgets", type=int, default=12, help="Warn if a dashboard exceeds this widget count")
    args = parser.parse_args()

findings: list[str] = []
    files = iter_files(args.paths)
    for path in files:
        findings.extend(audit_file(path, args.max_widgets))

if not files:
        findings.append("HIGH no analytics asset files matched the provided paths")

summary = f"Scanned {len(files)} analytics asset file(s); {len(findings)} finding(s) detected."
    return emit_result(findings, summary)

