    @AuraEnabled
    public static void closeAccount(Id accountId) {
        Account accountRecord = [SELECT Id, Status__c FROM Account WHERE Id = :accountId];
        accountRecord.Status__c = 'Closed';
        update accountRecord;
    }
}
