        SObjectAccessDecision decision = Security.stripInaccessible(
            AccessType.READABLE,
            [SELECT Id, Subject, Description, Internal_Notes__c FROM Case WHERE Status = 'Open']
        );
        return (List<Case>) decision.getRecords();
    }
}
