## Anti-Pattern: Coverage Test With No Useful Assertion

**What practitioners do:** They call the method, catch any exception, and assert only that execution reached the end.

```apex
@isTest
static void coverageOnly() {
    Test.startTest();
    AccountService.markCustomersActive(new List<Account>());
    Test.stopTest();
    System.assert(true);
}
```

**What goes wrong:** This proves nothing about the service contract, negative behavior, or actual data changes. Coverage rises while regression risk stays high.

**Correct approach:** Assert the expected record state, expected exception, or expected side effect with enough specificity that a real regression would fail the test.

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Check Apex test classes for weak assertions, org-data dependence, and async test mistakes."
    )
    parser.add_argument(
        "--manifest-dir",
        default=".",
        help="Root directory to scan for Apex classes.",
    )
    return parser.parse_args()

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def iter_apex_files(root: Path) -> list[Path]:
    return sorted(path for path in root.rglob("*.cls") if path.is_file())

def audit_test_class(path: Path) -> list[str]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")
    if not TEST_CLASS_RE.search(text):
        return findings

if SEE_ALL_DATA_RE.search(text):
        findings.append(f"HIGH {path}: test class uses `SeeAllData=true`; verify org-data dependency is truly required")

if not ASSERT_RE.search(text):
        findings.append(f"CRITICAL {path}: test class has no obvious assertions")

if ASYNC_CALL_RE.search(text) and not (START_TEST_RE.search(text) and STOP_TEST_RE.search(text)):
        findings.append(f"HIGH {path}: async behavior detected without a complete `Test.startTest()` / `Test.stopTest()` boundary")

if HARD_CODED_ID_RE.search(text):
        findings.append(f"MEDIUM {path}: hard-coded Salesforce-style ID literal found in test class")

if text.lower().count("@istest") + text.lower().count(" testmethod ") >= 3 and not TEST_SETUP_RE.search(text):
        if len(INSERT_RE.findall(text)) >= 4:
            findings.append(f"REVIEW {path}: multiple test methods with repeated inserts but no `@testSetup`; consider shared setup")

if "System.assert(true" in text.replace(" ", "") or "System.assertEquals(true" in text.replace(" ", ""):
        findings.append(f"MEDIUM {path}: assertion pattern suggests coverage-only verification")

return findings

def main() -> int:
    args = parse_args()
    root = Path(args.manifest_dir)
    if not root.exists():
        return emit_result([f"HIGH {root}: manifest directory not found"], "Scanned 0 Apex classes; manifest directory was missing.")

files = iter_apex_files(root)
    if not files:
        return emit_result([f"HIGH {root}: no Apex classes found"], "Scanned 0 Apex classes; no .cls files were found.")

findings: list[str] = []
    tested = 0
    for path in files:
        file_findings = audit_test_class(path)
        if TEST_CLASS_RE.search(path.read_text(encoding="utf-8", errors="ignore")):
            tested += 1
        findings.extend(file_findings)

if tested == 0:
        findings.append(f"REVIEW {root}: no Apex test classes detected in the scanned tree")
    summary = f"Scanned {len(files)} Apex class file(s); evaluated {tested} test class(es); {len(findings)} finding(s) detected."
    return emit_result(findings, summary)

### Minimal Handler Pattern

Keep the body tiny and move full examples to `references/examples.md`.

```apex
trigger AccountTrigger on Account (before insert, before update, after insert, after update) {
    if (!TriggerControl.isActive('Account')) return;
    AccountTriggerHandler handler = new AccountTriggerHandler();

    if (Trigger.isBefore && Trigger.isInsert) handler.onBeforeInsert(Trigger.new);
    if (Trigger.isBefore && Trigger.isUpdate) handler.onBeforeUpdate(Trigger.new, Trigger.oldMap);
    if (Trigger.isAfter && Trigger.isInsert) handler.onAfterInsert(Trigger.new);
    if (Trigger.isAfter && Trigger.isUpdate) handler.onAfterUpdate(Trigger.new, Trigger.oldMap);
}
```

- Trigger body delegates immediately.
- Activation guard runs first.
- Handler methods only exist for contexts that matter.
- Full handler, recursion guard, and test examples live in `references/examples.md`.

## Example 1: Complete Single-Trigger Pattern with Activation Bypass

```apex
// AccountTrigger.trigger
trigger AccountTrigger on Account (
    before insert, before update, before delete,
    after insert, after update, after delete, after undelete
) {
    // Activation bypass — disable without deployment
    Trigger_Setting__mdt[] settings = [
        SELECT Is_Active__c FROM Trigger_Setting__mdt
        WHERE Object_API_Name__c = 'Account' LIMIT 1
    ];
    if (!settings.isEmpty() && !settings[0].Is_Active__c) return;

    AccountTriggerHandler handler = new AccountTriggerHandler();
    if (Trigger.isBefore) {
        if (Trigger.isInsert) handler.onBeforeInsert(Trigger.new);
        if (Trigger.isUpdate) handler.onBeforeUpdate(Trigger.new, Trigger.oldMap);
        if (Trigger.isDelete) handler.onBeforeDelete(Trigger.old);
    }
    if (Trigger.isAfter) {
        if (Trigger.isInsert)   handler.onAfterInsert(Trigger.new);
        if (Trigger.isUpdate)   handler.onAfterUpdate(Trigger.new, Trigger.oldMap);
        if (Trigger.isDelete)   handler.onAfterDelete(Trigger.oldMap);
        if (Trigger.isUndelete) handler.onAfterUndelete(Trigger.new);
    }
}
```

