#!/usr/bin/env python3
"""Audit Apex trigger files for structural framework issues."""

from __future__ import annotations

import argparse
import json
import re
import sys
from collections import defaultdict
from pathlib import Path

TRIGGER_RE = re.compile(r"trigger\s+(\w+)\s+on\s+(\w+)", re.IGNORECASE)
HANDLER_RE = re.compile(r"Handler", re.IGNORECASE)
ACTIVATION_RE = re.compile(r"TriggerSettings__c|Trigger_Setting__mdt|isActive\s*\(", re.IGNORECASE)
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def iter_files(paths: list[str]) -> list[Path]:
    files: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_file():
            files.append(path)
        elif path.is_dir():
            files.extend(candidate for candidate in path.rglob("*.trigger") if candidate.is_file())
            files.extend(candidate for candidate in path.rglob("*.cls") if candidate.is_file())
    return sorted(set(files))

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_trigger(path: Path) -> tuple[list[str], tuple[str, str] | None]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")
    match = TRIGGER_RE.search(text)
    if not match:
        return findings, None

trigger_name, object_name = match.groups()
    lines = text.splitlines()
    body_lines = [line.strip() for line in lines if line.strip() and not line.strip().startswith("//")]
    if any("[" in line or " insert " in line.lower() or " update " in line.lower() for line in body_lines[1:]):
        findings.append(f"HIGH {path}: trigger body appears to contain logic instead of pure delegation")
    if not HANDLER_RE.search(text):
        findings.append(f"HIGH {path}: no obvious handler delegation found in trigger body")
    if not ACTIVATION_RE.search(text):
        findings.append(f"MEDIUM {path}: no activation bypass pattern found")
    if "Trigger.isAfter" in text and "update " in text.lower() and "processed" not in text.lower():
        findings.append(f"REVIEW {path}: after-trigger DML detected; confirm recursion guard exists in handler")
    return findings, (trigger_name, object_name)

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check Apex trigger files for common framework and operability issues."
    )
    parser.add_argument("paths", nargs="+", help="Files or directories to inspect")
    args = parser.parse_args()

files = iter_files(args.paths)
    if not files:
        return emit_result(
            ["HIGH no trigger or Apex files matched the provided paths"],
            "Scanned 0 files; no matching trigger or Apex files were found.",
        )

findings: list[str] = []
    triggers_by_object: defaultdict[str, list[str]] = defaultdict(list)
    scanned_triggers = 0
    for path in files:
        if path.suffix == ".trigger":
            scanned_triggers += 1
            trigger_findings, info = audit_trigger(path)
            findings.extend(trigger_findings)
            if info:
                _, object_name = info
                triggers_by_object[object_name].append(str(path))

for object_name, trigger_paths in triggers_by_object.items():
        if len(trigger_paths) > 1:
            findings.append(
                f"CRITICAL {object_name}: multiple trigger files detected ({', '.join(trigger_paths)})"
            )

summary = f"Scanned {scanned_triggers} trigger file(s); {len(findings)} finding(s) detected."
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def iter_files(root: Path) -> list[Path]:
    return sorted(path for path in root.rglob("*.cls") if path.is_file())

def audit_file(path: Path) -> list[str]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")
    if AMOUNT_QUERY_RE.search(text) and not (CURRENCY_ISO_RE.search(text) or CONVERT_RE.search(text)):
        findings.append(f"REVIEW {path}: SOQL selects `Amount` without obvious `CurrencyIsoCode` or `convertCurrency()` usage; verify currency context is not being lost")
    if HARDCODED_CODE_RE.search(text):
        findings.append(f"REVIEW {path}: hardcoded currency code literal found; verify currency assumptions are not fixed to one market")
    return findings

def main() -> int:
    args = parse_args()
    root = Path(args.manifest_dir)
    if not root.exists():
        return emit_result([f"HIGH {root}: manifest directory not found"], "Scanned 0 Apex files; manifest directory was missing.")
    files = iter_files(root)
    if not files:
        return emit_result([f"HIGH {root}: no Apex files found"], "Scanned 0 Apex files; no .cls files were found.")
    findings: list[str] = []
    for path in files:
        findings.extend(audit_file(path))
    summary = f"Scanned {len(files)} Apex file(s); {len(findings)} currency-management finding(s) detected."
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Audit roll-up summary alternatives for scale and metadata-limit risks."""

from __future__ import annotations

import argparse
import json
import re
import sys
from pathlib import Path

SUMMARY_FIELD_RE = re.compile(r"<type>\s*Summary\s*</type>|<summarizedField>", re.IGNORECASE)
AGG_SOQL_RE = re.compile(r"\[\s*SELECT\b.*\b(COUNT|SUM|AVG|MIN|MAX)\s*\(", re.IGNORECASE)
LOOP_RE = re.compile(r"\b(for|while)\b")
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Check metadata and Apex for weak roll-up summary alternative patterns.")
    parser.add_argument("--manifest-dir", default=".", help="Root directory to scan for metadata and Apex.")
    return parser.parse_args()

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def iter_summary_fields(root: Path) -> list[Path]:
    return sorted(path for path in root.rglob("*field-meta.xml") if path.is_file())

def iter_apex(root: Path) -> list[Path]:
    return sorted(path for path in root.rglob("*") if path.is_file() and path.suffix.lower() in {".cls", ".trigger"})

def main() -> int:
    args = parse_args()
    root = Path(args.manifest_dir)
    if not root.exists():
        return emit_result([f"HIGH {root}: manifest directory not found"], "Scanned 0 files; manifest directory was missing.")

findings: list[str] = []
    summary_fields = [path for path in iter_summary_fields(root) if SUMMARY_FIELD_RE.search(path.read_text(encoding="utf-8", errors="ignore"))]
    if len(summary_fields) >= 35:
        findings.append(f"REVIEW {root}: {len(summary_fields)} roll-up summary field metadata file(s) found; verify the org is not approaching native summary limits")

for path in iter_apex(root):
        text = path.read_text(encoding="utf-8", errors="ignore")
        loop_depth = 0
        for line_number, raw_line in enumerate(text.splitlines(), start=1):
            line = raw_line.strip()
            if LOOP_RE.search(line) and "for each" not in line.lower():
                loop_depth += line.count("{") or 1
            if loop_depth > 0 and AGG_SOQL_RE.search(line):
                findings.append(f"HIGH {path}:{line_number}: aggregate SOQL found inside a loop; collect parent IDs and aggregate once")
            if "}" in line and loop_depth > 0:
                loop_depth = max(0, loop_depth - line.count("}"))

scanned = len(summary_fields) + len(iter_apex(root))
    if scanned == 0:
        return emit_result([f"HIGH {root}: no relevant metadata or Apex files found"], "Scanned 0 files; no roll-up-related files were found.")
    summary = f"Scanned {scanned} file(s); {len(findings)} roll-up-alternative finding(s) detected."
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def iter_files(root: Path) -> list[Path]:
    return sorted(path for path in root.rglob("*.cls") if path.is_file())

def audit_file(path: Path) -> list[str]:
    findings: list[str] = []
    text = path.read_text(encoding="utf-8", errors="ignore")
    if DYNAMIC_SOSL_RE.search(text) and CONCAT_RE.search(text):
        findings.append(f"HIGH {path}: dynamic `Search.query()` appears to concatenate input; review for SOSL injection risk")
    if SEARCH_METHOD_RE.search(text) and LIKE_SEARCH_RE.search(text):
        findings.append(f"REVIEW {path}: search-oriented Apex appears to use SOQL `LIKE`; confirm SOSL is not the better fit")
    return findings

def main() -> int:
    args = parse_args()
    root = Path(args.manifest_dir)
    if not root.exists():
        return emit_result([f"HIGH {root}: manifest directory not found"], "Scanned 0 Apex files; manifest directory was missing.")
    files = iter_files(root)
    if not files:
        return emit_result([f"HIGH {root}: no Apex files found"], "Scanned 0 Apex files; no .cls files were found.")
    findings: list[str] = []
    for path in files:
        findings.extend(audit_file(path))
    summary = f"Scanned {len(files)} Apex file(s); {len(findings)} SOSL finding(s) detected."
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Review Flow metadata for missing fault connectors and weak error handling."""

from __future__ import annotations

import argparse
import json
import sys
import xml.etree.ElementTree as ET
from pathlib import Path

FLOW_SUFFIX = ".flow-meta.xml"
RISKY_ELEMENTS = {"recordCreates", "recordDeletes", "recordLookups", "recordUpdates", "actionCalls", "subflows"}
SEVERITY_WEIGHTS = {"CRITICAL": 20, "HIGH": 10, "MEDIUM": 5, "LOW": 1, "REVIEW": 0}

def local_name(tag: str) -> str:
    return tag.split("}", 1)[-1]

def child_text(element: ET.Element, child_name: str) -> str:
    for child in element:
        if local_name(child.tag) == child_name:
            return (child.text or "").strip()
    return ""

def has_child(element: ET.Element, child_name: str) -> bool:
    return any(local_name(child.tag) == child_name for child in element)

def iter_flow_files(paths: list[str]) -> list[Path]:
    files: list[Path] = []
    for raw in paths:
        path = Path(raw)
        if path.is_dir():
            files.extend(candidate for candidate in path.rglob(f"*{FLOW_SUFFIX}") if candidate.is_file())
        elif path.is_file() and path.name.endswith(FLOW_SUFFIX):
            files.append(path)
    return sorted(set(files))

def normalize_finding(finding: str) -> dict[str, str]:
    severity, _, remainder = finding.partition(" ")
    location = ""
    message = remainder
    if ": " in remainder:
        location, message = remainder.split(": ", 1)
    return {"severity": severity or "INFO", "location": location, "message": message}

def emit_result(findings: list[str], summary: str) -> int:
    normalized = [normalize_finding(item) for item in findings]
    score = max(0, 100 - sum(SEVERITY_WEIGHTS.get(item["severity"], 0) for item in normalized))
    print(json.dumps({"score": score, "findings": normalized, "summary": summary}, indent=2))
    return 1 if normalized else 0

def audit_flow(path: Path) -> list[str]:
    findings: list[str] = []
    root = ET.parse(path).getroot()
    for child in root:
        tag_name = local_name(child.tag)
        if tag_name not in RISKY_ELEMENTS:
            continue
        label = child_text(child, "label") or child_text(child, "name") or "<unnamed element>"
        if not has_child(child, "faultConnector"):
            findings.append(f"HIGH {path}: `{label}` ({tag_name}) has no fault connector")

fault_message_mentions = 0
    for text_node in root.iter():
        if text_node.text and "$Flow.FaultMessage" in text_node.text:
            fault_message_mentions += 1
    if fault_message_mentions == 0:
        findings.append(f"REVIEW {path}: no $Flow.FaultMessage usage found; confirm diagnostic detail is captured elsewhere")

return findings

def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check Flow metadata for missing fault connectors and weak diagnostic handling."
    )
    parser.add_argument("paths", nargs="+", help="Flow metadata files or directories")
    args = parser.parse_args()

files = iter_flow_files(args.paths)
    if not files:
        return emit_result(
            ["HIGH no Flow metadata files found"],
            "Scanned 0 Flow metadata file(s); no matching .flow-meta.xml files were found.",
        )

findings: list[str] = []
    for path in files:
        findings.extend(audit_flow(path))

summary = f"Scanned {len(files)} Flow metadata file(s); {len(findings)} finding(s) detected."
    return emit_result(findings, summary)

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Checker script for Flow Bulkification skill."""

from __future__ import annotations

import argparse
import sys
from pathlib import Path
from xml.etree import ElementTree as ET

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Check Flow Bulkification configuration and metadata for common issues.",
    )
    parser.add_argument(
        "--manifest-dir",
        default=".",
        help="Root directory of the Salesforce metadata (default: current directory).",
    )
    return parser.parse_args()

def local_name(tag: str) -> str:
    return tag.rsplit("}", 1)[-1]

def text_of(element: ET.Element, child_name: str) -> str:
    for child in element:
        if local_name(child.tag) == child_name and child.text:
            return child.text.strip()
    return ""

def parse_flow(path: Path) -> ET.Element | None:
    try:
        return ET.parse(path).getroot()
    except ET.ParseError:
        return None

def check_flow_bulkification(manifest_dir: Path) -> list[str]:
    issues: list[str] = []

if not manifest_dir.exists():
        issues.append(f"Manifest directory not found: {manifest_dir}")
        return issues

flow_paths = sorted(manifest_dir.rglob("*.flow-meta.xml"))
    for flow_path in flow_paths:
        root = parse_flow(flow_path)
        if root is None:
            issues.append(f"{flow_path}: unable to parse flow metadata.")
            continue

loop_names = {
            text_of(elem, "name")
            for elem in root.iter()
            if local_name(elem.tag) == "loops" and text_of(elem, "name")
        }
        if not loop_names:
            continue

risk_tags = {"recordLookups", "recordCreates", "recordUpdates", "recordDeletes", "actionCalls", "subflows"}
        risky_targets: list[str] = []

for elem in root.iter():
            tag = local_name(elem.tag)
            name = text_of(elem, "name")
            targets = {
                child.text.strip()
                for child in elem.iter()
                if local_name(child.tag) == "targetReference" and child.text
            }
            if tag in risk_tags and name and targets & loop_names:
                risky_targets.append(f"{tag}:{name}")

if risky_targets:
            issues.append(
                f"{flow_path}: data or action elements appear immediately after a loop ({', '.join(sorted(risky_targets))}); confirm no query, DML, Apex action, or subflow runs per iteration."
            )
            continue

data_element_count = sum(
            1 for elem in root.iter() if local_name(elem.tag) in risk_tags
        )
        if data_element_count >= 3:
            issues.append(
                f"{flow_path}: flow contains {len(loop_names)} loop(s) and {data_element_count} data/action elements; review for hidden bulkification risks even if operations are not directly attached to the loop."
            )

return issues

def main() -> int:
    args = parse_args()
    manifest_dir = Path(args.manifest_dir)
    issues = check_flow_bulkification(manifest_dir)

if not issues:
        print("No issues found.")
        return 0

for issue in issues:
        print(f"ISSUE: {issue}")

return 1

if __name__ == "__main__":
    sys.exit(main())

## Example 2: Generic SObject Action Editor

**Context:** A Flow action needs admins to map a generic input object and select which record variable to pass.

**Problem:** Free-form configuration creates incompatible inputs across Flows.

**Solution:**

```js
this.dispatchEvent(
    new CustomEvent('configuration_editor_input_value_changed', {
        detail: {
            name: 'recordVariableName',
            newValue: selectedValue,
            newValueDataType: 'String'
        }
    })
);
```

**Why it works:** The builder contract stays explicit, and the editor can validate the selected variable before Flow admins save the configuration.

