            if not has_fault:
                issues.append(
                    f"{flow_path}: scheduled element `{label}` has no fault connector; background automation should fail observably."
                )

return issues

def main() -> int:
    args = parse_args()
    issues = check_scheduled_flows(Path(args.manifest_dir))

if not issues:
        print("No issues found.")
        return 0

for issue in issues:
        print(f"ISSUE: {issue}")

return 1

